    """Compute rolling beta vs market (SPY)."""
    def _beta(x_y):
        x = x_y[:len(x_y)//2]
        y = x_y[len(x_y)//2:]
        if len(x) < 5 or y.std() == 0:
            return np.nan
        covariance = np.cov(x, y)[0, 1]
        market_var = np.var(y)
