def compute_rolling_beta(self, asset_returns: pd.Series,
                        market_returns: pd.Series, window: int) -> pd.Series:
    """Compute rolling beta vs market (SPY)."""
    def _beta(asset_window, market_window):
        if len(market_window) < 5 or market_window.std() == 0:
            return np.nan
        try:
            return np.polyfit(market_window, asset_window, 1)[0]
        except:
            return np.nan

    result = []
    for i in range(len(asset_returns)):
        if i < window - 1:
            result.append(np.nan)
        else:
            asset_win = asset_returns.iloc[i-window+1:i+1].values
            market_win = market_returns.iloc[i-window+1:i+1].values
            result.append(_beta(asset_win, market_win))

    return pd.Series(result, index=asset_returns.index)

